insert into public.stocks (ticker, company_name, sector, description, logo_url) values
  -- Cryptocurrencies
  ('BTC',   'Bitcoin',                              'Cryptocurrency', 'The original cryptocurrency and largest by market cap. A decentralized digital currency secured by proof-of-work, designed as a peer-to-peer store of value and medium of exchange.',                                                                                'https://assets.coingecko.com/coins/images/1/large/bitcoin.png'),
  ('ETH',   'Ethereum',                             'Cryptocurrency', 'The leading programmable blockchain platform. Ethereum hosts the majority of decentralized finance (DeFi), NFTs, and smart contracts running on its proof-of-stake network.',                                                                                        'https://assets.coingecko.com/coins/images/279/large/ethereum.png'),
  ('BNB',   'BNB',                                  'Cryptocurrency', 'Native token of the BNB Chain ecosystem, used to pay fees on Binance Exchange and BNB Smart Chain. Powers one of the most active blockchain networks for DeFi applications.',                                                                                       'https://assets.coingecko.com/coins/images/825/large/bnb-icon2_2x.png'),
  ('SOL',   'Solana',                               'Cryptocurrency', 'A high-performance Layer 1 blockchain known for sub-second finality and low transaction fees. Solana supports a wide ecosystem of DeFi protocols, NFT marketplaces, and consumer apps.',                                                                             'https://assets.coingecko.com/coins/images/4128/large/solana.png'),
  ('XRP',   'XRP',                                  'Cryptocurrency', 'Ripple''s digital asset designed for fast, low-cost international money transfers. XRP serves as a bridge currency in RippleNet, enabling real-time gross settlement between financial institutions.',                                                                'https://assets.coingecko.com/coins/images/44/large/xrp-symbol-white-128.png'),
  ('ADA',   'Cardano',                              'Cryptocurrency', 'A proof-of-stake blockchain platform built on peer-reviewed academic research. Cardano aims to provide a secure and scalable infrastructure for decentralized applications and digital identity.',                                                                   'https://assets.coingecko.com/coins/images/975/large/cardano.png'),
  ('AVAX',  'Avalanche',                            'Cryptocurrency', 'A fast, low-cost smart contract platform with sub-second transaction finality. Avalanche uses a novel three-chain architecture and supports custom subnets, making it a top choice for institutional DeFi.',                                                          'https://assets.coingecko.com/coins/images/12559/large/Avalanche_Circle_RedWhite_Trans.png'),
  ('DOT',   'Polkadot',                             'Cryptocurrency', 'A multi-chain network that enables different blockchains to transfer messages and value in a trust-free fashion. Polkadot connects specialized blockchains called parachains into a unified network.',                                                               'https://assets.coingecko.com/coins/images/12171/large/polkadot.png'),
  ('LINK',  'Chainlink',                            'Cryptocurrency', 'The leading decentralized oracle network that connects smart contracts with real-world data, APIs, and payment systems. LINK token is used to pay node operators for delivering off-chain data.',                                                                    'https://assets.coingecko.com/coins/images/877/large/chainlink-new-logo.png'),
  ('MATIC', 'Polygon',                              'Cryptocurrency', 'Ethereum''s leading Layer 2 scaling solution offering fast, cheap transactions while inheriting Ethereum''s security. Polygon''s PoS chain supports a vast ecosystem of games, DeFi, and NFT applications.',                                                       'https://assets.coingecko.com/coins/images/3890/large/polygon.png'),
  -- ETFs
  ('SPY',   'SPDR S&P 500 ETF Trust',               'ETF',           'The most-traded ETF in the world, tracking the S&P 500 index of large-cap U.S. stocks. Provides instant diversification across 500 of America''s biggest companies in a single trade.',                                                                              'https://static2.finnhub.io/file/publicdatany/finnhubimage/stock_logo/SPY.png'),
  ('QQQ',   'Invesco QQQ Trust',                    'ETF',           'Tracks the Nasdaq-100, the 100 largest non-financial companies on the Nasdaq. Heavily weighted toward mega-cap technology, making it a benchmark for tech-sector growth.',                                                                                            'https://logo.clearbit.com/invesco.com'),
  ('IWM',   'iShares Russell 2000 ETF',             'ETF',           'Tracks the Russell 2000 index of U.S. small-cap stocks. Exposure to roughly 2,000 smaller companies, offering diversified access to domestically-focused businesses and higher-growth potential.',                                                                   'https://logo.clearbit.com/ishares.com'),
  ('DIA',   'SPDR Dow Jones Industrial Avg ETF',    'ETF',           'Tracks the 30-stock Dow Jones Industrial Average, the oldest and most-cited U.S. equity benchmark. Holds the same blue-chip companies featured in Stockr''s core swipe deck.',                                                                                       'https://static2.finnhub.io/file/publicdatany/finnhubimage/stock_logo/DIA.png'),
  ('VTI',   'Vanguard Total Stock Market ETF',      'ETF',           'Broad exposure to the entire U.S. equity market — large, mid, small, and micro-cap — in one fund. One of the most widely held ETFs by long-term, buy-and-hold investors.',                                                                                           'https://logo.clearbit.com/vanguard.com'),
  ('VOO',   'Vanguard S&P 500 ETF',                 'ETF',           'Vanguard''s low-cost version of the S&P 500 index fund. Favored by passive investors for its rock-bottom expense ratio and reliable tracking of America''s 500 largest companies.',                                                                                  'https://logo.clearbit.com/vanguard.com'),
  ('GLD',   'SPDR Gold Shares',                     'ETF',           'The largest gold-backed ETF, giving investors direct exposure to the price of gold bullion without physically storing it. Often used as a hedge against inflation and market downturns.',                                                                             'https://static2.finnhub.io/file/publicdatany/finnhubimage/stock_logo/GLD.png'),
  ('TLT',   'iShares 20+ Year Treasury Bond ETF',  'ETF',           'Tracks long-duration U.S. Treasury bonds with maturities of 20 years or more. Highly sensitive to interest rate changes and widely used as a safe-haven asset and rate-direction trade.',                                                                            'https://logo.clearbit.com/ishares.com'),
  ('XLK',   'Technology Select Sector SPDR Fund',  'ETF',           'Concentrated exposure to U.S. technology companies within the S&P 500, including software, hardware, semiconductors, and IT services. One of the top-performing sector ETFs of the past decade.',                                                                    'https://static2.finnhub.io/file/publicdatany/finnhubimage/stock_logo/XLK.png'),
  ('VNQ',   'Vanguard Real Estate ETF',             'ETF',           'Tracks U.S. real estate investment trusts (REITs), offering exposure to commercial property, residential, industrial, and healthcare real estate. Provides income through REIT dividend distributions.',                                                              'https://logo.clearbit.com/vanguard.com'),
  ('EEM',   'iShares MSCI Emerging Markets ETF',   'ETF',           'Tracks the MSCI Emerging Markets index, covering large and mid-cap equities across 24 developing economies including China, India, Brazil, and Taiwan. High growth potential with elevated geopolitical risk.',                                                        'https://logo.clearbit.com/ishares.com'),
  ('EFA',   'iShares MSCI EAFE ETF',               'ETF',           'Tracks the MSCI EAFE index of large and mid-cap developed-market stocks across Europe, Australasia, and the Far East. A core international diversifier for U.S.-based investors.',                                                                                    'https://logo.clearbit.com/ishares.com'),
  ('ARKK',  'ARK Innovation ETF',                  'ETF',           'An actively managed ETF run by ARK Invest targeting disruptive innovation across genomics, AI, robotics, fintech, and space exploration. Known for high conviction, high volatility, high-growth bets.',                                                               'https://logo.clearbit.com/ark-funds.com'),
  ('BND',   'Vanguard Total Bond Market ETF',      'ETF',           'Broad exposure to the entire U.S. investment-grade bond market — government, corporate, and mortgage-backed securities. The benchmark choice for fixed-income allocation in a diversified portfolio.',                                                                 'https://logo.clearbit.com/vanguard.com'),
  ('VYM',   'Vanguard High Dividend Yield ETF',    'ETF',           'Tracks high dividend-yielding U.S. stocks, weighted toward value-oriented sectors like financials, healthcare, and consumer staples. Favored by income investors seeking reliable quarterly distributions.',                                                           'https://logo.clearbit.com/vanguard.com')
on conflict (ticker) do update set
  company_name = excluded.company_name,
  sector       = excluded.sector,
  description  = excluded.description,
  logo_url     = excluded.logo_url;
